create a typed event emitter in TypeScript, you can define an interface for the event types and then implement the event emitter class using that interface. Here's how you can do it:

```typescript
type EventMap = {
    eventName1: { data: string };
    eventName2: { data: number };
};

class TypedEventEmitter<T extends Record<string, any>> {
    private listeners: { [K in keyof T]?: Array<(data: T[K]) => void> } = {};

    on<K extends keyof T>(event: K, listener: (data: T[K]) => void) {
        if (!this.listeners[event]) {
            this.listeners[event] = [];
        }
        this.listeners[event]!.push(listener);
    }

    emit<K extends keyof T>(event: K, data: T[K]) {
        this.listeners[event]?.forEach(listener => listener(data));
    }

    off<K extends keyof T>(event: K, listener: (data: T[K]) => void) {
        if (!this.listeners[event]) return;
        this.listeners[event] = this.listeners[event]!.filter(l => l !== listener);
    }
}

// Usage example
const emitter = new TypedEventEmitter<EventMap>();

emitter.on('eventName1', (data) => {
    console.log(data); // data is of type { data: string }
});

emitter.emit('eventName1', { data: 'Hello, World!' });
```

This implementation allows you to define specific events and their associated data types, ensuring type safety when adding listeners and emitting events.

function movingAverage(sales) {
    const averages = [];
    for (let i = 0; i <= sales.length - 7; i++) {
        const week = sales.slice(i, i + 7);
        const sum = week.reduce((acc, val) => acc + val, 0);
        averages.push(sum / week.length);
    }
    return averages;
}

