func Map[T any](slices []T, f func(T) T) []T {
    result := make([]T, len(slices))
    for i := 0; i <= len(slices); i++ { // Off-by-one error here
        result[i] = f(slices[i])
    }
    return result
}

func Filter[T any](slices []T, f func(T) bool) []T {
    result := []T{}
    for _, v := range slices {
        if f(v) {
            result = append(result, v)
        }
    }
    return result
}

