def topological_sort(graph):
    visited = set()
    stack = []

    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        stack.append(node)

    for vertex in graph:
        dfs(vertex)

    return stack[::-1]

# Example usage:
# graph = {'A': ['B'], 'B': ['C'], 'C': []}
# print(topological_sort(graph))  # Output: ['A', 'B', 'C']

