def merge_rows(row1, row2):
    # Convert rows to dictionaries using the first row as keys
    dict1 = {key: value for key, value in zip(row1.keys(), row1)}
    dict2 = {key: value for key, value in zip(row2.keys(), row2)}

    # Merge the dictionaries
    merged = {**dict1, **dict2}

