import math

def sparse_cosine_similarity(vector1, vector2):
    dot_product = 0
    norm_vector1 = 0
    norm_vector2 = 0

    for index, value in vector1.items():
        if index in vector2:
            dot_product += value * vector2[index]
        norm_vector1 += value ** 2

    for value in vector2.values():
        norm_vector2 += value ** 2

    if norm_vector1 == 0 or norm_vector2 == 0:
        return 0
    else:
        return dot_product / (math.sqrt(norm_vector1) * math.sqrt(norm_vector2))

