use reqwest;
use snafu::Snafu;

#[derive(Debug, Snafu)]
#[snafu(visibility(pub(crate))]
pub enum Error {
    UnexpectedResponse { status_code: StatusCode, body: Bytes },
    BuildRequestError { source: reqwest::Error },
    ExecuteRequestError { source: reqwest::Error },
    ResponseBytesError { source: reqwest::Error },
    DeserializeError { source: Error, body: Bytes },
    GetTokenError { source: AzureError },
}

pub async fn delete_event(
    operation_config: &crate::OperationConfig,
    event_id: &str,
) -> Result<(), Error> {
    let url = format!("{}/events/{}", operation_config.base_url, event_id);
    let client = reqwest::Client::new();

    let response = client
        .delete(&url)
        .send()
        .await
        .map_err(|source| Error::BuildRequestError { source })?;

    if response.status().is_success() {
