import UIKit

class CustomView: UIView {

    private func prepareProperties(_ leftControls: Array<UIControl>?, rightControls: Array<UIControl>?) {
        if let leftControls = leftControls {
            for control in leftControls {
                addSubview(control)
                control.translatesAutoresizingMaskIntoConstraints = false
                if let previousControl = subviews.last?.previousSibling {
                    control.topAnchor.constraint(equalTo: previousControl.bottomAnchor, constant: 8).isActive = true
                } else {
                    control.topAnchor.constraint(equalTo: topAnchor, constant: 8).isActive = true
                }
                control.leadingAnchor.constraint(equalTo: leadingAnchor, constant: 8).isActive = true
                control.trailingAnchor.constraint(equalTo: centerXAnchor, constant: -8).isActive = true
            }
        }

        if let rightControls = rightControls {
            for control in rightControls {
                addSubview(control)
                control.translatesAutoresizingMaskIntoConstraints = false
                if let previousControl = subviews.last?.previousSibling {
                    control.topAnchor.constraint(equalTo: previousControl.bottomAnchor, constant: 8).isActive = true
                } else {
                    control.topAnchor.constraint(equalTo: topAnchor, constant: 8).isActive = true
                }
                control.leadingAnchor.constraint(equalTo: centerXAnchor, constant: 8).isActive = true
                control.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -8).isActive = true
            }
        }
    }

