import hmac
import os
import random
import string

class SecurePasswordManager:
    def __init__(self):
        self.secret_key = os.urandom(16)  # Generate a secret key for HMAC

    def generate_password(self, length: int) -> str:
        characters = string.ascii_letters + string.digits
        return ''.join(random.choice(characters) for _ in range(length))

    def hash_password(self, password: str) -> str:
        return hmac.new(self.secret_key, password.encode(), 'sha256').hexdigest()

    def verify_password(self, password: str, hashed_password: str) -> bool:
        return hmac.compare_digest(hashed_password, self.hash_password(password))

# Demonstration of using SecurePasswordManager
