        menuSystem.AddTopMenuItem("Edit");
        menuSystem.AddSubMenuItem("Edit", "Cut");
        menuSystem.AddSubMenuItem("Edit", "Copy");
        menuSystem.DisplayMenuHierarchy();
    }
}
