class SchemaGenerator {
    public function createSchema($backend, $schemaDefinitions) {
        $sqlCommands = [];

        foreach ($schemaDefinitions as $table => $columns) {
            $sql = "CREATE TABLE $table (";
            $columnDefs = [];
            foreach ($columns as $columnName => $columnType) {
                $columnDefs[] = "$columnName $columnType";
            }
            $sql .= implode(", ", $columnDefs);
            $sql .= ");";
            $sqlCommands[] = $sql;
