func extractReferencesAndLocations(_ input: String) -> [(String, Int)] {
    var referencesAndLocations: [(String, Int)] = []
    var locationOffset = 0

    let items = input.components(separatedBy: ",")
    for item in items {
        locationOffset += item.count + 1 // 1 for comma
        let reference = item.components(separatedBy: "=")
            .first?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .components(separatedBy: .whitespaces)
            .last
        if let reference = reference {
            referencesAndLocations.append((reference, locationOffset - item.count - 1))
        }
    }

    return referencesAndLocations
}

