fn process_greeting(props: Option<&str>) -> Result<String, ()> {
    if let Some(greeting) = props {
        let parsed_greeting: Result<String, _> = serde_json::from_str(greeting)
            .and_then(|value: serde_json::Value| value["greeting"].as_str().map(|s| s.to_string()).ok_or(()));
        return parsed_greeting.map_err(|_| ());
    }
    Err(())
