#include <iostream>
#include <vector>
#include <string>
#include <unordered_set>

int countUniqueHeaderFiles(const std::vector<std::string>& includedFiles) {
    std::unordered_set<std::string> uniqueFiles;

    for (const std::string& file : includedFiles) {
