func parseSPMManifest(_ filePath: String) -> [String: Any]? {
    guard let fileContent = try? String(contentsOfFile: filePath) else {
        return nil
    }

    var packageName: String?
    var dependencies: [String] = []
    var targets: [[String: String]] = []

    let lines = fileContent.components(separatedBy: .newlines)
    for line in lines {
        if let name = line.extractValue(for: "name: ") {
            packageName = name
        } else if let dependency = line.extractValue(for: ".package(url: \"", end: "\"") {
            dependencies.append(dependency)
        } else if let targetName = line.extractValue(for: "name: \"") {
            if let targetPath = lines[lines.firstIndex(of: line)! + 1].extractValue(for: "path: \"") {
                targets.append(["name": targetName, "path": targetPath])
            }
        }
    }

    if let packageName = packageName {
        return [
            "packageName": packageName,
            "dependencies": dependencies,
            "targets": targets
        ]
    } else {
        return nil
    }
}

extension String {
    func extractValue(for start: String, end: String? = nil) -> String? {
        guard let startIndex = self.range(of: start)?.upperBound else {
            return nil
        }
        if let end = end, let endIndex = self.range(of: end, range: startIndex..<self.endIndex)?.lowerBound {
            return String(self[startIndex..<endIndex])
        } else {
            return String(self[startIndex...].dropLast())
        }
    }
}
```

The `parseSPMManifest` function reads the content of the SPM manifest file, extracts the package name, dependencies, and target information, and returns a dictionary containing the extracted data. The `extractValue` extension method is used to extract values from specific patterns in the file content.

