public class TPDUSizeCalculator {

    /**
     * Calculates and returns the maximum TPDUSize. This is equal to 2^(maxTPDUSizeParam)
     * 
     * @param maxTPDUSizeParam
     *            the size parameter
     * @return the maximum TPDU size
     * @throws IllegalArgumentException if maxTPDUSizeParam is out of bound
     */
    public static int calculateMaxTPDUSize(int maxTPDUSizeParam) {
        if (maxTPDUSizeParam < 7 || maxTPDUSizeParam > 16) {
            throw new IllegalArgumentException("maxTPDUSizeParam is out of bound");
        }
        return (int) Math.pow(2, maxTPDUSizeParam);
    }

    public static void main(String[] args) {
        // Test the function with valid input
        int validMaxTPDUSizeParam = 10;
        System.out.println("Maximum TPDU size for valid input: " + calculateMaxTPDUSize(validMaxTPDUSizeParam));

