use std::error::Error;
use std::fmt;

#[derive(Debug, PartialEq)]
enum Action {
    Allow,
    KillThread,
    Deny,
}

struct Filter {
    action: Action,
    rules: Vec<(Action, usize)>,
}

#[derive(Debug, PartialEq)]
struct FilterError {
    message: String,
}

impl fmt::Display for FilterError {
    fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
        write!(f, "{}", self.message)
    }
}

impl Error for FilterError {}

impl Filter {
    fn new(action: Action) -> Result<Filter, FilterError> {
        Ok(Filter {
            action,
            rules: Vec::new(),
        })
    }

    fn add_rule(&mut self, action: Action, syscall_arg_index: usize) -> Result<(), FilterError> {
        let num_args = 6; // Assume 6 syscall arguments for demonstration purposes

        if syscall_arg_index >= num_args {
            return Err(FilterError {
                message: "Invalid syscall argument index".to_string(),
            });
        }

        self.rules.push((action, syscall_arg_index));
        Ok(())
    }
}

fn test_bad_add_rule() {
    let mut filter = Filter::new(Action::Allow).unwrap();

    // Trying to match on the "6th" syscall argument (does not exist) will fail with EINVAL.
    assert_eq!(
        filter.add_rule(Action::KillThread, 6),
        Err(FilterError {
            message: "Invalid syscall argument index".to_string()
        })
    );
}

fn main() {
    test_bad_add_rule();
}
