func displayImages(_ images: [UIImage], in imageView: UIImageView) {
    for img in images {
        if img.size.width > imageView.frame.size.width || img.size.height > imageView.frame.size.height {
            let aspectFitRect = AVMakeRect(aspectRatio: img.size, insideRect: imageView.bounds)
            let scaledImage = img.scaledImage(with: aspectFitRect.size)
            imageView.image = scaledImage
        } else {
            imageView.image = img
        }
    }
}

extension UIImage {
    func scaledImage(with size: CGSize) -> UIImage {
        UIGraphicsBeginImageContextWithOptions(size, false, 0.0)
        self.draw(in: CGRect(origin: .zero, size: size))
        let newImage = UIGraphicsGetImageFromCurrentImageContext()
        UIGraphicsEndImageContext()
        return newImage ?? self
    }
}
```

In the solution, the `displayImages` function iterates through the array of images. For each image, it checks if the width or height exceeds the dimensions of the image view. If so, it calculates the aspect-fit rectangle for the image within the image view and then scales down the image using the `scaledImage` method. Finally, it sets the scaled image to the image view. If the image fits within the image view, it is displayed as is. The `scaledImage` method is an extension of UIImage that scales the image to the specified size while maintaining its aspect ratio.

