class StudentManager:
    def __init__(self):
        self.students = []

    def add_student(self, student):
        # Add a new student to the list
        self.students.append(student)

    def get_student_info(self, student_id):
        # Retrieve information for a specific student
        for student in self.students:
            if student.id == student_id:
                return student
        return None

    def calculate_average_gpa(self):
        # Calculate the average GPA of all students
        total_gpa = sum(student.gpa for student in self.students)
        return total_gpa / len(self.students) if self.students else 0

    def filter_students(self, criteria):
        # Filter students based on the given criteria
        filtered_students = []
        for student in self.students:
            if criteria(student):
                filtered_students.append(student)
        return filtered_students
