import torch

def deep_to(data, device, non_blocking=False):
    if isinstance(data, (list, tuple)):
        return type(data)(deep_to(item, device, non_blocking) for item in data)
    elif isinstance(data, dict):
        return {key: deep_to(value, device, non_blocking) for key, value in data.items()}
    else:
        return torch.tensor(data, device=device, non_blocking=non_blocking) if isinstance(data, (int, float)) else data

