class Monoid:
    def __init__(self, set_elements, binary_operation):
        self.set_elements = set_elements
        self.binary_operation = binary_operation

    def is_associative(self):
        for a in self.set_elements:
            for b in self.set_elements:
                for c in self.set_elements:
                    if self.binary_operation(self.binary_operation(a, b), c) != self.binary_operation(a, self.binary_operation(b, c)):
                        return False
        return True

    def has_identity(self):
        for e in self.set_elements:
            has_identity = True
            for a in self.set_elements:
                if self.binary_operation(e, a) != a or self.binary_operation(a, e) != a:
                    has_identity = False
                    break
            if has_identity:
                return True
        return False
```

