from typing import List

def canCross(stones: List[int]) -> bool:
    # Create a set to store the positions of the stones for quick lookup
    stone_set = set(stones)

    # Create a dictionary to store the possible jumps from each stone
    jumps = {stone: set() for stone in stones}
    jumps[0].add(0)  # The frog starts at the first stone with a jump of 0

    for stone in stones:
        for jump in jumps[stone]:
            for next_jump in range(jump - 1, jump + 2):
                if next_jump > 0 and stone + next_jump in stone_set:
                    jumps[stone + next_jump].add(next_jump)

    # If the last stone has any valid jumps, the frog can cross the river
    return bool(jumps[stones[-1]])
```

