func skipHours(startTime: String, hoursToSkip: Int) -> String {
    let timeComponents = startTime.components(separatedBy: ":")
    guard let hours = Int(timeComponents[0]), let minutes = Int(timeComponents[1]) else {
        return "Invalid time format"
    }

    let totalMinutes = hours * 60 + minutes
    let newTotalMinutes = (totalMinutes + (hoursToSkip * 60)) % (24 * 60)

    let newHours = newTotalMinutes / 60
    let newMinutes = newTotalMinutes % 60

    let formattedHours = String(format: "%02d", newHours)
    let formattedMinutes = String(format: "%02d", newMinutes)

    return "\(formattedHours):\(formattedMinutes)"
}

