Write the `font(forName:size:)` method of the `FontManager` class that fulfills the requirements mentioned above.

```swift
class FontManager {
    func font(forName name: String, size: CGFloat) -> UIFont {
        if name == "system" {
            return UIFont.systemFont(ofSize: size)
        }
        if name.contains("system") {
            let systemName = name.replacingOccurrences(of: "system", with: "").lowercased()
            let weight: UIFont.Weight?
            switch systemName {
                case "black":
                    weight = UIFont.Weight.black
                case "heavy":
                    weight = UIFont.Weight.heavy
                case "light":
                    weight = UIFont.Weight.light
                case "medium":
                    weight = UIFont.Weight.medium
                default:
                    weight = nil
            }
            if let weight = weight {
                return UIFont.systemFont(ofSize: size, weight: weight)
            }
        }
        // If the font name is not "system" or does not contain "system" followed by a weight, return a custom font
        return UIFont(name: name, size: size) ?? UIFont.systemFont(ofSize: size)
    }
