function resolveModulePath(importPath, importingModulePath) {
  if (importPath.startsWith("./")) {
    const importSegments = importPath.split("/");
    const importingSegments = importingModulePath.split("/");
    importingSegments.pop(); // Remove the importing module's filename
    importSegments.shift(); // Remove the leading "./"
    return importingSegments.concat(importSegments).join("/");
  } else if (importPath.startsWith("../")) {
    const importSegments = importPath.split("/");
    const importingSegments = importingModulePath.split("/");
    importingSegments.pop(); // Remove the importing module's filename
    importSegments.shift(); // Remove the leading "../"
    while (importSegments[0] === "..") {
      importSegments.shift();
      importingSegments.pop();
    }
    return importingSegments.concat(importSegments).join("/");
  } else {
    return importPath;
  }
}

