struct Target {
    let name: String
    let dependencies: [String]
}

func resolveDependencies(_ targets: [Target]) -> [String] {
    var dependencyGraph: [String: Set<String>] = [:]
    var indegree: [String: Int] = [:]

    for target in targets {
        dependencyGraph[target.name] = Set(target.dependencies)
        indegree[target.name] = 0
    }

    for (_, dependencies) in dependencyGraph {
        for dependency in dependencies {
            indegree[dependency, default: 0] += 1
        }
    }

    var queue: [String] = []
    for (target, count) in indegree {
        if count == 0 {
            queue.append(target)
        }
    }

    var result: [String] = []
    while !queue.isEmpty {
        let current = queue.removeFirst()
        result.append(current)
        if let dependencies = dependencyGraph[current] {
            for dependency in dependencies {
                indegree[dependency, default: 0] -= 1
                if indegree[dependency, default: 0] == 0 {
                    queue.append(dependency)
                }
            }
        }
    }

    return result
}

