        this.databases = dbs;
        this.isCountQuery = isCount;
    }

    // Method to execute the query and return the results
    public List<Result> executeQuery(String query) {
        if (isCountQuery) {
            // Execute count query on all databases
            List<Result> results = new ArrayList<>();
            for (Database db : databases) {
                results.add(db.executeCountQuery(query));
            }
            return results;
        } else {
            // Execute regular query on all databases
            List<Result> results = new ArrayList<>();
            for (Database db : databases) {
                results.add(db.executeQuery(query));
            }
            return results;
        }
    }
