    fn new() -> Self {
        Leaderboard { players: Vec::new() }
    }

    fn add_score(&mut self, player: String, score: i32) {
        if let Some(p) = self.players.iter_mut().find(|p| p.name == player) {
            p.score += score;
        } else {
            self.players.push(Player::new(player, score));
        }
        self.players.sort_by(|a, b| b.score.cmp(&a.score));
    }

    fn top(&self, k: i32) -> Vec<(String, i32)> {
        self.players.iter().take(k as usize).map(|p| (p.name.clone(), p.score)).collect()
    }

    fn reset(&mut self, player: String) {
        if let Some(p) = self.players.iter_mut().find(|p| p.name == player) {
            p.score = 0;
        }
    }
}
