// Simplified implementation of the effect system using RxJS

// Create a simplified version of the observable class
class Observable {
  constructor(subscribe) {
    this._subscribe = subscribe;
  }

  subscribe(observer) {
    return this._subscribe(observer);
  }

  pipe(...operators) {
    return operators.reduce((source, operator) => operator(source), this);
  }
}

// Create a simplified version of the createEffect function
function createEffect(callback) {
  return new Observable(observer => {
    const result = callback().subscribe({
      next: value => observer.next(value),
      error: err => observer.error(err),
      complete: () => observer.complete(),
    });

    return {
      unsubscribe() {
        result.unsubscribe();
      }
    };
  });
}

// Implement simplified versions of the operators
function ofType(actionType) {
  return source => new Observable(observer => {
    return source.subscribe({
      next: value => {
        if (value.type === actionType) {
          observer.next(value);
        }
      },
      error: err => observer.error(err),
      complete: () => observer.complete(),
    });
  });
}

function filter(predicate) {
  return source => new Observable(observer => {
    return source.subscribe({
      next: value => {
        if (predicate(value)) {
          observer.next(value);
        }
      },
      error: err => observer.error(err),
      complete: () => observer.complete(),
    });
  });
}

function mergeMap(callback) {
  return source => new Observable(observer => {
    return source.subscribe({
      next: value => {
        callback(value).subscribe({
          next: innerValue => observer.next(innerValue),
          error: err => observer.error(err),
          complete: () => observer.complete(),
        });
      },
      error: err => observer.error(err),
      complete: () => observer.complete(),
    });
  });
}

function map(callback) {
  return source => new Observable(observer => {
    return source.subscribe({
      next: value => observer.next(callback(value)),
      error: err => observer.error(err),
      complete: () => observer.complete(),
    });
  });
}

// Usage example
const actions = new Observable(observer => {
  observer.next({ type: 'loadProfile' });
  observer.next({ type: 'otherAction' });
  observer.complete();
});

const authService = {
  authenticated: true
};

const profileService = {
  fetchProfile: () => new Observable(observer => {
    setTimeout(() => {
      observer.next({ name: 'John Doe' });
      observer.complete();
    }, 1000);
  })
};

createEffect(() =>
  actions.pipe(
    ofType('loadProfile'),
    filter(() => authService.authenticated),
    mergeMap(() => profileService.fetchProfile()),
    map(profile => console.log('Profile loaded:', profile))
  )
).subscribe();
