use std::time::Duration;
use smallvec::SmallVec;

struct Config {
    parallelism: Option<i32>,
    num_results: Option<i32>,
    rpc_timeout: Option<Duration>,
    add_provider: Option<SmallVec<[i32; 8]>>,
}

fn parse_config(config_content: &str) -> Config {
    let mut parsed_config = Config {
        parallelism: None,
        num_results: None,
        rpc_timeout: None,
        add_provider: None,
    };

    for line in config_content.lines() {
        let parts: Vec<&str> = line.split(':').collect();
        if parts.len() == 2 {
            let key = parts[0].trim();
            let value = parts[1].trim();

            match key {
                "parallelism" => parsed_config.parallelism = Some(value.parse().unwrap()),
                "num_results" => parsed_config.num_results = Some(value.parse().unwrap()),
                "rpc_timeout" => {
                    let duration = value.trim_start_matches("Duration::from_secs(").trim_end_matches("),");
                    parsed_config.rpc_timeout = Some(Duration::from_secs(duration.parse().unwrap()));
                }
                "add_provider" => {
                    let provider: SmallVec<[i32; 8]> = value.parse().unwrap();
                    parsed_config.add_provider = Some(provider);
                }
                _ => {}
            }
        }
    }

    parsed_config
}

fn main() {
    let config_content = "parallelism,
    num_results: 20,
    rpc_timeout: Duration::from_secs(8),
    add_provider: SmallVec::new(),";

    let parsed_config = parse_config(config_content);
    println!("{:?}", parsed_config);
}
```

