import Foundation

class Stack<T> {
    private var elements: [T] = []

    func push(_ val: T) {
        elements.append(val)
    }

    func pop() -> T? {
        return elements.popLast()
    }

    func peek() -> T? {
        return elements.last
    }

    func isEmpty() -> Bool {
        return elements.isEmpty
    }
}

class StackWithMax {
    private var stack: Stack<Int> = Stack<Int>()
    private var maxStack: Stack<Int> = Stack<Int>()

    func push(_ val: Int) {
        stack.push(val)
        if maxStack.isEmpty() || val >= maxStack.peek()! {
            maxStack.push(val)
        }
    }

    func pop() -> Int? {
        if stack.isEmpty() {
            return nil
        }
        let val = stack.pop()
        if val == maxStack.peek() {
            maxStack.pop()
        }
        return val
    }

    func max() -> Int? {
        return maxStack.peek()
    }
}
