public class ServiceRuleDTOSerializer extends StdSerializer<ServiceRuleDTO> {

    public ServiceRuleDTOSerializer() {
        this(null);
    }

    public ServiceRuleDTOSerializer(Class<ServiceRuleDTO> t) {
        super(t);
    }

    @Override
    public void serialize(ServiceRuleDTO value, JsonGenerator gen, SerializerProvider provider) throws IOException {
        gen.writeStartObject();
        if (value.getId() != null) {
            gen.writeStringField("id", value.getId().toString());
        }
        if (value.getName() != null && !value.getName().isEmpty()) {
            gen.writeStringField("name", value.getName());
        }
        if (value.getDescription() != null && !value.getDescription().isEmpty()) {
            gen.writeStringField("description", value.getDescription());
        }
        if (value.getPriority() != null) {
            gen.writeNumberField("priority", value.getPriority());
        }
        gen.writeEndObject();
    }

    public static void main(String[] args) {
        SimpleModule module = new SimpleModule();
        module.addSerializer(ServiceRuleDTO.class, new ServiceRuleDTOSerializer());
        SimpleSerializers serializers = new SimpleSerializers();
        serializers.addSerializer(new ServiceRuleDTOSerializer());
    }
