class Version:
    def __init__(self, version_str):
        self.major, self.minor, self.patch = map(int, version_str.split('.'))

    def __eq__(self, other):
        return (self.major, self.minor, self.patch) == (other.major, other.minor, other.patch)

    def __ne__(self, other):
        return not self == other

    def __lt__(self, other):
        return (self.major, self.minor, self.patch) < (other.major, other.minor, other.patch)

    def __gt__(self, other):
        return (self.major, self.minor, self.patch) > (other.major, other.minor, other.patch)

    def __le__(self, other):
        return self < other or self == other

    def __ge__(self, other):
        return self > other or self == other

    def increment_patch(self, amount):
        self.patch += amount

    def __str__(self):
        return f"{self.major}.{self.minor}.{self.patch}"
```
This `Version` class allows for the creation and comparison of software versions, as well as the ability to increment the patch version. The comparison operations are implemented based on the major, minor, and patch versions of the software.

