from typing import List, Dict

def process_rules(rules: List[str]) -> Dict[str, List[str]]:
    result = {"section_rules": [], "entity_rules": []}
    for rule in rules:
        if rule.startswith("section_"):
            start_index = rule.index("[") + 1
            end_index = rule.index("]")
            section_rules = rule[start_index:end_index].split(", ")
            result["section_rules"].extend(section_rules)
        elif rule.startswith("entity_"):
            entity_rule = rule.split("_")[1]
            result["entity_rules"].append(entity_rule)
    return result
