import fs from 'fs';
import path from 'path';

function searchDatasetTxtInTmp() {
  const tmpDir = '/tmp';
  const results = [];

  function walk(dir) {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        walk(fullPath);
      } else if (entry.isFile() && entry.name.toLowerCase() === 'dataset.txt') {
        results.push(fullPath);
      }
    }
  }

  walk(tmpDir);
  return results;
}

