function openNotesToml() {
  const candidates = [
    path.join(process.cwd(), 'notes.toml'),
    path.join(os.homedir(), 'notes.toml'),
  ];

  for (const filePath of candidates) {
    if (fs.existsSync(filePath)) {
      return fs.readFileSync(filePath, 'utf8');
    }
  }

  return '';
}

