function finishEvalScript(todoNote) {
  const lines = todoNote.split('\n');
  const output = [];
  let inEval = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.trim().startsWith('eval:')) {
      inEval = true;
      continue;
    }

    if (inEval && line.trim() === '') {
      inEval = false;
      continue;
    }

    if (inEval) {
      output.push(line.replace(/^\s*-\s?/, ''));
    }
  }

  return output.join('\n');
}

def add_meeting_summary(result_path, summary):
    lines = []
    found = False

    with open(result_path, "r", encoding="utf-8") as f:
        for line in f:
            if line.startswith("meeting_summary"):
                lines.append(f'meeting_summary = "{summary}"\n')
                found = True
            else:
                lines.append(line)

    if not found:
        if lines and not lines[-1].endswith("\n"):
            lines[-1] += "\n"
        lines.append(f'meeting_summary = "{summary}"\n')

    with open(result_path, "w", encoding="utf-8") as f:
        f.writelines(lines)

import os

def search_minutes_docx():
    desktop = os.path.join(os.path.expanduser("~"), "Desktop")
    matches = []
    for root, dirs, files in os.walk(desktop):
        for file in files:
            if "minutes" in file.lower() and file.lower().endswith(".docx"):
                matches.append(os.path.join(root, file))
    return matches

