type DraftState<T> = {
  value: T;
  isDraft: boolean;
};

export function openDraft<T>(value: T): DraftState<T> {
  return {
    value: Array.isArray(value) ? ([...value] as unknown as T) : value,
    isDraft: true,
  };
}

const fs = require('fs');

function createOutputCsv(summary) {
  const lines = ['section,content'];
  for (const item of summary) {
    const section = String(item.section).replace(/"/g, '""');
    const content = String(item.content).replace(/"/g, '""');
    lines.push(`"${section}","${content}"`);
  }
  fs.writeFileSync('output.csv', lines.join('\n'));
}

