function findDeployLog(json) {
  if (typeof json === "string") {
    json = JSON.parse(json);
  }

  if (!json || typeof json !== "object") {
    return null;
  }

  if (json.deploy_log) {
    return json.deploy_log;
  }

  for (const key in json) {
    const value = json[key];
    if (value && typeof value === "object") {
      const found = findDeployLog(value);
      if (found) {
        return found;
      }
    }
  }

  return null;
}

function findDraftLog(logs, draftId) {
  for (let i = logs.length - 1; i >= 0; i--) {
    const entry = logs[i];
    if (entry.id == draftId && entry.status === "draft") {
      return entry;
    }
  }
  return null;
}

