function findAndAttach(filename, ext, contact) {
  const matches = [];
  const target = `${filename}.${ext}`.toLowerCase();

  function walk(dir) {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        walk(fullPath);
      } else if (entry.isFile() && entry.name.toLowerCase() === target) {
        matches.push(fullPath);
      }
    }
  }

  walk(process.cwd());

  if (matches.length === 0) {
    throw new Error(`File not found: ${target}`);
  }

  const filePath = matches[0];
  const mail = {
    to: contact,
    subject: `Requested file: ${filename}.${ext}`,
    body: `Please find the requested file attached.`,
    attachments: [{ path: filePath }]
  };

  return sendEmail(mail);
}

function searchAndSend(filename, ext, contact) {
  const query = `${filename}.${ext}`;
  const results = [];

  function walk(dir) {
    const entries = fs.readdirSync(dir);
    for (const entry of entries) {
      const fullPath = path.join(dir, entry);
      const stat = fs.statSync(fullPath);
      if (stat.isDirectory()) {
        walk(fullPath);
      } else if (entry.toLowerCase() === query.toLowerCase()) {
        results.push(fullPath);
      }
    }
  }

  walk(process.cwd());

  if (results.length > 0) {
    sendToContact(contact, results[0]);
  }
}
